const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const rideOptions = JSON.parse(localStorage.getItem('ride_options') || '[]');
const rideSearches = JSON.parse(localStorage.getItem('ride_searches') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');

const homePlace = places.find(p => p.id === 'place_123_maple_st');
const stationPlace = places.find(p => p.id === 'place_downtown_central_station');
const validRideSearchIds = new Set(rideSearches.map(r => r.id));

// Find trips that match route, timing, vehicle category, payment method, and budget, and that are linked to a runtime ride search
const candidateTripData = trips
  .filter(trip => {
    if (!homePlace || !stationPlace) return false;
    if (trip.status !== 'upcoming') return false;
    if (trip.tripType !== 'immediate') return false;
    if (trip.paymentMethod !== 'cash') return false;
    if (trip.vehicleCategory !== 'economy') return false;
    if (typeof trip.estimatedFare !== 'number' || trip.estimatedFare > 20) return false;
    if (trip.pickupPlaceId !== homePlace.id) return false;
    if (trip.dropoffPlaceId !== stationPlace.id) return false;
    if (!trip.rideOptionId) return false;
    const opt = rideOptions.find(o => o.id === trip.rideOptionId);
    if (!opt) return false;
    const rs = rideSearches.find(r => r.id === opt.rideSearchId);
    if (!rs || !validRideSearchIds.has(opt.rideSearchId)) return false;
    return true;
  })
  .map(trip => {
    const opt = rideOptions.find(o => o.id === trip.rideOptionId) || null;
    const rs = opt ? rideSearches.find(r => r.id === opt.rideSearchId) || null : null;
    return { trip, opt, rs };
  })
  .filter(x => x.opt && x.rs && validRideSearchIds.has(x.opt.rideSearchId));

// CP1 (0.5): User booked an upcoming immediate cash economy trip from Home to Station under $20 based on a runtime ride search
const hasCorrectTrip = candidateTripData.length > 0;
checkpoints.push({ passed: hasCorrectTrip, weight: 0.5 });

// CP2 (0.5): For at least one such trip, the chosen ride option is the cheapest economy option under $20 for that search
let choseCheapest = false;
for (const ct of candidateTripData) {
  const rsId = ct.opt.rideSearchId;
  const eligible = rideOptions.filter(o => {
    if (o.rideSearchId !== rsId) return false;
    if (!o.available) return false;
    if (o.vehicleCategory !== 'economy') return false;
    if (typeof o.estimatedFare !== 'number' || o.estimatedFare > 20) return false;
    return true;
  });
  if (!eligible.length) continue;
  const minFare = Math.min(...eligible.map(o => o.estimatedFare));
  if (Math.abs(ct.opt.estimatedFare - minFare) < 1e-6) {
    choseCheapest = true;
    break;
  }
}
checkpoints.push({ passed: choseCheapest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const rideOptions = JSON.parse(localStorage.getItem('ride_options') || '[]');
const rideSearches = JSON.parse(localStorage.getItem('ride_searches') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');
const promos = JSON.parse(localStorage.getItem('promo_codes') || '[]');

const residentialPlaceIds = places.filter(p => p.type === 'street_address').map(p => p.id);
const airportPlaceIds = places.filter(p => p.type === 'airport_terminal').map(p => p.id);
const validRideSearchIds = new Set(rideSearches.map(r => r.id));

function timeHHMM(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  const hh = String(d.getUTCHours()).padStart(2, '0');
  const mm = String(d.getUTCMinutes()).padStart(2, '0');
  return hh + ':' + mm;
}

// Candidate trips: upcoming scheduled sedan, card, residential -> airport, <= $35, at 08:30
let candidateTrips = trips
  .map(trip => {
    if (trip.status !== 'upcoming') return null;
    if (trip.tripType !== 'scheduled') return null;
    if (trip.paymentMethod !== 'card') return null;
    if (trip.vehicleCategory !== 'sedan') return null;
    if (typeof trip.estimatedFare !== 'number' || trip.estimatedFare > 35) return null;
    if (!residentialPlaceIds.includes(trip.pickupPlaceId)) return null;
    if (!airportPlaceIds.includes(trip.dropoffPlaceId)) return null;
    if (!trip.rideOptionId) return null;
    const opt = rideOptions.find(o => o.id === trip.rideOptionId);
    if (!opt) return null;
    const rs = rideSearches.find(r => r.id === opt.rideSearchId);
    if (!rs || !validRideSearchIds.has(opt.rideSearchId)) return null;
    // time check: 08:30 local (we approximate with UTC HH:MM)
    if (timeHHMM(rs.pickupDatetime) !== '08:30') return null;
    const promo = trip.promoCodeId ? promos.find(p => p.id === trip.promoCodeId) || null : null;
    return { trip, opt, rs, promo };
  })
  .filter(x => x && x.opt && x.rs);

// CP1 (0.4): At least one upcoming scheduled card sedan trip from residential to airport at 08:30 with estimated fare <= 35
const hasBasicTrip = candidateTrips.length > 0;
checkpoints.push({ passed: hasBasicTrip, weight: 0.4 });

// Filter to those with a valid promo applied to sedan and a real discount
const promoTrips = candidateTrips.filter(ct => {
  if (!ct.trip.promoCodeId || !ct.promo) return false;
  if (ct.rs.appliedPromoCodeId !== ct.promo.id) return false;
  const applicable = !Array.isArray(ct.promo.applicableVehicleCategories) || ct.promo.applicableVehicleCategories.includes('sedan');
  if (!applicable) return false;
  const baseFare = typeof ct.opt.originalEstimatedFare === 'number' ? ct.opt.originalEstimatedFare : ct.opt.estimatedFare;
  const discountedOption = typeof ct.opt.estimatedFare === 'number' && ct.opt.estimatedFare <= baseFare;
  const discountedTrip = typeof ct.trip.estimatedFare === 'number' && ct.trip.estimatedFare <= baseFare;
  return discountedOption && discountedTrip;
});

// CP2 (0.3): Promo for sedan correctly applied to at least one such trip
const hasCorrectPromo = promoTrips.length > 0;
checkpoints.push({ passed: hasCorrectPromo, weight: 0.3 });

// CP3 (0.3): For at least one such promo trip, chosen option is the cheapest sedan option under $35 for that search
let choseCheapestSedan = false;
for (const ct of promoTrips) {
  const rsId = ct.opt.rideSearchId;
  const eligible = rideOptions.filter(o => {
    if (o.rideSearchId !== rsId) return false;
    if (!o.available) return false;
    if (o.vehicleCategory !== 'sedan') return false;
    if (typeof o.estimatedFare !== 'number' || o.estimatedFare > 35) return false;
    return true;
  });
  if (!eligible.length) continue;
  const minFare = Math.min(...eligible.map(o => o.estimatedFare));
  if (Math.abs(ct.opt.estimatedFare - minFare) < 1e-6) {
    choseCheapestSedan = true;
    break;
  }
}
checkpoints.push({ passed: choseCheapestSedan, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const rideOptions = JSON.parse(localStorage.getItem('ride_options') || '[]');
const rideSearches = JSON.parse(localStorage.getItem('ride_searches') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');

const streetIds = places.filter(p => p.type === 'street_address').map(p => p.id);
const mallIds = places.filter(p => p.type === 'shopping_mall').map(p => p.id);
const parkIds = places.filter(p => p.type === 'park').map(p => p.id);
const validRideSearchIds = new Set(rideSearches.map(r => r.id));

// Candidate trips: upcoming immediate card minivan_xl, 3 passengers, street -> mall -> park, under $40, linked to runtime search
const candidateTripData = trips
  .filter(trip => {
    if (trip.status !== 'upcoming') return false;
    if (trip.tripType !== 'immediate') return false;
    if (trip.paymentMethod !== 'card') return false;
    if (trip.vehicleCategory !== 'minivan_xl') return false;
    if (typeof trip.passengerCount !== 'number' || trip.passengerCount < 3) return false;
    if (!streetIds.includes(trip.pickupPlaceId)) return false;
    if (!parkIds.includes(trip.dropoffPlaceId)) return false;
    if (!Array.isArray(trip.stopPlaceIds) || !trip.stopPlaceIds.some(id => mallIds.includes(id))) return false;
    if (typeof trip.estimatedFare !== 'number' || trip.estimatedFare > 40) return false;
    if (!trip.rideOptionId) return false;
    const opt = rideOptions.find(o => o.id === trip.rideOptionId);
    if (!opt) return false;
    const rs = rideSearches.find(r => r.id === opt.rideSearchId);
    if (!rs || !validRideSearchIds.has(opt.rideSearchId)) return false;
    return true;
  })
  .map(trip => {
    const opt = rideOptions.find(o => o.id === trip.rideOptionId) || null;
    const rs = opt ? rideSearches.find(r => r.id === opt.rideSearchId) || null : null;
    return { trip, opt, rs };
  })
  .filter(x => x.opt && x.rs && validRideSearchIds.has(x.opt.rideSearchId));

// CP1 (0.4): At least one upcoming immediate card Minivan/XL multi-stop trip for 3 passengers with the correct route and fare under $40
const hasCorrectTrip = candidateTripData.length > 0;
checkpoints.push({ passed: hasCorrectTrip, weight: 0.4 });

// CP2 (0.3): For at least one such trip, the associated ride search used a passenger capacity filter of at least 4
const filteredByCapacity = candidateTripData.filter(ct => typeof ct.rs.minPassengerCapacity === 'number' && ct.rs.minPassengerCapacity >= 4);
const usedCapacityFilter = filteredByCapacity.length > 0;
checkpoints.push({ passed: usedCapacityFilter, weight: 0.3 });

// CP3 (0.3): For at least one capacity-filtered trip, chosen option is the cheapest Minivan/XL option under $40 for that search
let choseCheapestMinivan = false;
for (const ct of filteredByCapacity) {
  const rsId = ct.opt.rideSearchId;
  const eligible = rideOptions.filter(o => {
    if (o.rideSearchId !== rsId) return false;
    if (!o.available) return false;
    if (o.vehicleCategory !== 'minivan_xl') return false;
    if (typeof o.estimatedFare !== 'number' || o.estimatedFare > 40) return false;
    return true;
  });
  if (!eligible.length) continue;
  const minFare = Math.min(...eligible.map(o => o.estimatedFare));
  if (Math.abs(ct.opt.estimatedFare - minFare) < 1e-6) {
    choseCheapestMinivan = true;
    break;
  }
}
checkpoints.push({ passed: choseCheapestMinivan, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const places = JSON.parse(localStorage.getItem('places') || '[]');
const savedPlacesRaw = JSON.parse(localStorage.getItem('saved_places') || '[]');
const rideSearches = JSON.parse(localStorage.getItem('ride_searches') || '[]');
const rideOptions = JSON.parse(localStorage.getItem('ride_options') || '[]');
const trips = JSON.parse(localStorage.getItem('trips') || '[]');

const streetIds = places.filter(p => p.type === 'street_address').map(p => p.id);
const libraryIds = places.filter(p => p.type === 'library').map(p => p.id);

const savedPlaces = savedPlacesRaw.map(sp => ({
  ...sp,
  place: places.find(p => p.id === sp.placeId) || null
}));

const homeSaved = savedPlaces.filter(sp => sp.label && sp.label.toLowerCase() === 'home' && sp.place && streetIds.includes(sp.place.id));
const workSaved = savedPlaces.filter(sp => sp.label && sp.label.toLowerCase() === 'work' && sp.place && streetIds.includes(sp.place.id));

// CP1 (0.3): User has saved both a Home and a Work address pointing to street addresses
const hasHomeAndWork = homeSaved.length > 0 && workSaved.length > 0;
checkpoints.push({ passed: hasHomeAndWork, weight: 0.3 });

const workPlaceIds = workSaved.map(sp => sp.placeId);

// Ride searches from saved Work address to a library, immediate (now)
const workLibrarySearches = rideSearches.filter(rs => {
  if (rs.pickupType !== 'now') return false;
  if (!workPlaceIds.includes(rs.pickupPlaceId)) return false;
  if (!libraryIds.includes(rs.dropoffPlaceId)) return false;
  return true;
});

// CP2 (0.3): User started at least one immediate search from Work to a library
const hasWorkToLibrarySearch = workLibrarySearches.length > 0;
checkpoints.push({ passed: hasWorkToLibrarySearch, weight: 0.3 });

// Upcoming immediate standard taxi trip from Work to library whose ride option belongs to one of these searches
const workLibrarySearchIds = new Set(workLibrarySearches.map(rs => rs.id));
const candidateTrips = trips
  .filter(trip => {
    if (trip.status !== 'upcoming') return false;
    if (trip.tripType !== 'immediate') return false;
    if (!workPlaceIds.includes(trip.pickupPlaceId)) return false;
    if (!libraryIds.includes(trip.dropoffPlaceId)) return false;
    if (trip.vehicleCategory !== 'standard') return false;
    if (!trip.rideOptionId) return false;
    const opt = rideOptions.find(o => o.id === trip.rideOptionId);
    if (!opt) return false;
    return workLibrarySearchIds.has(opt.rideSearchId);
  });

// CP3 (0.4): At least one upcoming immediate standard taxi trip from saved Work to a library, tied to a corresponding Work->Library search
const hasStandardTripFromWork = candidateTrips.length > 0;
checkpoints.push({ passed: hasStandardTripFromWork, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const rideOptions = JSON.parse(localStorage.getItem('ride_options') || '[]');
const rideSearches = JSON.parse(localStorage.getItem('ride_searches') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');

const clinicIds = places.filter(p => p.type === 'clinic').map(p => p.id);
const communityIds = places
  .filter(p => p.type === 'poi' && (p.name || '').toLowerCase().includes('community center'))
  .map(p => p.id);
const validRideSearchIds = new Set(rideSearches.map(r => r.id));

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

// Define afternoon as 12:00-17:59 (approximation using UTC hours)
function isAfternoon(iso) {
  const d = parseDateSafe(iso);
  if (!d) return false;
  const h = d.getUTCHours();
  return h >= 12 && h < 18;
}

// Candidate trips: upcoming scheduled, clinic -> community center, wheelchair-accessible, under $30, in afternoon, linked to runtime search
const candidateTripData = trips
  .filter(trip => {
    if (trip.status !== 'upcoming') return false;
    if (trip.tripType !== 'scheduled') return false;
    if (!clinicIds.includes(trip.pickupPlaceId)) return false;
    if (!communityIds.includes(trip.dropoffPlaceId)) return false;
    if (!trip.wheelchairAccessible) return false;
    if (typeof trip.estimatedFare !== 'number' || trip.estimatedFare > 30) return false;
    if (!isAfternoon(trip.pickupDatetimePlanned)) return false;
    if (!trip.rideOptionId) return false;
    const opt = rideOptions.find(o => o.id === trip.rideOptionId);
    if (!opt) return false;
    const rs = rideSearches.find(r => r.id === opt.rideSearchId);
    if (!rs || !validRideSearchIds.has(opt.rideSearchId)) return false;
    return true;
  })
  .map(trip => {
    const opt = rideOptions.find(o => o.id === trip.rideOptionId) || null;
    const rs = opt ? rideSearches.find(r => r.id === opt.rideSearchId) || null : null;
    return { trip, opt, rs };
  })
  .filter(x => x.opt && x.rs && validRideSearchIds.has(x.opt.rideSearchId));

// CP1 (0.4): At least one upcoming scheduled afternoon trip from clinic to community center, wheelchair-accessible, under $30, based on a runtime search
const hasCorrectTrip = candidateTripData.length > 0;
checkpoints.push({ passed: hasCorrectTrip, weight: 0.4 });

// Filter to those where wheelchair filter and rating sort were applied
const filteredByAccessibilityAndSort = candidateTripData.filter(ct => {
  const af = Array.isArray(ct.rs.accessibilityFilter) ? ct.rs.accessibilityFilter : [];
  const hasWheelchairFilter = af.includes('wheelchair_accessible');
  const hasRatingSort = ct.rs.sortOption === 'rating_high_to_low';
  return hasWheelchairFilter && hasRatingSort;
});

// CP2 (0.3): Ride search used wheelchair-accessible filter AND rating-high-to-low sort
const usedFilterAndSort = filteredByAccessibilityAndSort.length > 0;
checkpoints.push({ passed: usedFilterAndSort, weight: 0.3 });

// CP3 (0.3): For at least one such trip, chosen option is the highest-rated wheelchair-accessible option under $30 for that search
let choseHighestRated = false;
for (const ct of filteredByAccessibilityAndSort) {
  const rsId = ct.opt.rideSearchId;
  const accessibleOptions = rideOptions.filter(o => {
    if (o.rideSearchId !== rsId) return false;
    if (!o.available) return false;
    if (!o.wheelchairAccessible) return false;
    if (typeof o.estimatedFare !== 'number' || o.estimatedFare > 30) return false;
    return true;
  });
  if (!accessibleOptions.length) continue;
  const sorted = accessibleOptions.slice().sort((a, b) => {
    const ra = typeof a.averageRating === 'number' ? a.averageRating : 0;
    const rb = typeof b.averageRating === 'number' ? b.averageRating : 0;
    if (rb !== ra) return rb - ra;
    const ca = a.ratingCount || 0;
    const cb = b.ratingCount || 0;
    return cb - ca;
  });
  const best = sorted[0];
  if (best && best.id === ct.opt.id) {
    choseHighestRated = true;
    break;
  }
}
checkpoints.push({ passed: choseHighestRated, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');

const airportPlaceIds = places.filter(p => p.type === 'airport_terminal').map(p => p.id);

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

function timeHHMM(iso) {
  const d = parseDateSafe(iso);
  if (!d) return null;
  const hh = String(d.getUTCHours()).padStart(2, '0');
  const mm = String(d.getUTCMinutes()).padStart(2, '0');
  return hh + ':' + mm;
}

// Identify the earliest upcoming scheduled airport trip (dynamic, not by hardcoded id)
const upcomingAirportTrips = trips.filter(t => t.status === 'upcoming' && t.tripType === 'scheduled' && airportPlaceIds.includes(t.dropoffPlaceId));
let targetTrip = null;
if (upcomingAirportTrips.length > 0) {
  targetTrip = upcomingAirportTrips.slice().sort((a, b) => {
    const ta = parseDateSafe(a.pickupDatetimePlanned) || 0;
    const tb = parseDateSafe(b.pickupDatetimePlanned) || 0;
    return ta - tb;
  })[0];
}

// CP1 (0.5): That earliest upcoming airport trip now has pickup time 08:45 (approx using UTC time)
const hasNewPickupTime = !!(targetTrip && timeHHMM(targetTrip.pickupDatetimePlanned) === '08:45');
checkpoints.push({ passed: hasNewPickupTime, weight: 0.5 });

// CP2 (0.5): That trip's vehicle category is now standard (upgraded from economy)
const hasStandardCategory = !!(targetTrip && targetTrip.vehicleCategory === 'standard');
checkpoints.push({ passed: hasStandardCategory, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

let baselineStart = null;
if (metadata && metadata.baselineDate) {
  baselineStart = new Date(metadata.baselineDate + 'T00:00:00Z');
}

// Determine the earliest future trip relative to the baseline date
const futureTrips = trips
  .map(t => ({ trip: t, time: parseDateSafe(t.pickupDatetimePlanned) }))
  .filter(x => x.time && (!baselineStart || x.time >= baselineStart))
  .sort((a, b) => a.time - b.time);

const earliestFuture = futureTrips.length > 0 ? futureTrips[0].trip : null;

const cancelledCorrectly = !!(earliestFuture &&
  earliestFuture.status === 'cancelled' &&
  earliestFuture.cancellationReason === 'change_of_plans' &&
  earliestFuture.refundMethod === 'wallet_credit' &&
  (!baselineStart || (earliestFuture.cancellationTime && parseDateSafe(earliestFuture.cancellationTime) >= baselineStart))
);

// Single checkpoint (1.0): Earliest future trip was cancelled with change_of_plans and wallet_credit after baseline
checkpoints.push({ passed: cancelledCorrectly, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const trips = JSON.parse(localStorage.getItem('trips') || '[]');
const tickets = JSON.parse(localStorage.getItem('support_tickets') || '[]');
const messages = JSON.parse(localStorage.getItem('support_messages') || '[]');

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

// Find most recent completed trip by planned pickup time
const completedTrips = trips
  .filter(t => t.status === 'completed' && t.pickupDatetimePlanned)
  .sort((a, b) => {
    const ta = parseDateSafe(a.pickupDatetimePlanned) || 0;
    const tb = parseDateSafe(b.pickupDatetimePlanned) || 0;
    return tb - ta; // descending: most recent first
  });

const mostRecent = completedTrips.length > 0 ? completedTrips[0] : null;
const mostRecentId = mostRecent ? mostRecent.id : null;

let ticketForRecent = null;
if (mostRecentId) {
  ticketForRecent = tickets.find(t =>
    t.tripId === mostRecentId &&
    t.topic === 'billing_issues' &&
    t.issueType === 'fare_higher_than_expected' &&
    (t.contactMethod === 'in_app_chat' || t.contactMethod === 'message_support')
  ) || null;
}

// CP1 (0.7): There is a billing-issues/fare_higher_than_expected ticket for the most recent completed trip, via in-app chat/message
const hasCorrectTicket = !!ticketForRecent;
checkpoints.push({ passed: hasCorrectTicket, weight: 0.7 });

// CP2 (0.3): User has sent at least one message on that ticket
let hasUserMessage = false;
if (ticketForRecent) {
  hasUserMessage = messages.some(m => m.ticketId === ticketForRecent.id && m.senderType === 'user');
}
checkpoints.push({ passed: !!ticketForRecent && hasUserMessage, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
